    vector<int> maximumCount(vector<int>& nums, vector<vector<int>>& queries) {
        vector<int> result;
        for (auto& query : queries) {
            int idx = query[0];
            int val = query[1];
            nums[idx] = val;
            int count = 0;
            for (int i = 0; i < nums.size(); i++) {
                if (isPrime(nums[i])) {
                    count++;
                }
            }
            result.push_back(count);
        }
        return result;
    }
    bool isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
};
